import type { PESection } from './content'

export const contextWindowsDe: Record<string, PESection> = {
  definition: { title: 'Kontextfenster erklärt: Warum KI vergisst', content: '**LLMs haben kein Langzeitgedächtnis — sie "sehen" nur ein Schiebefenster mit aktuellen Tokens, und alles außerhalb dieses Fensters wird vergessen oder komprimiert.** Dieser Artikel erklärt, was das für Ihre Prompts bedeutet und wie Sie innerhalb (und außerhalb) dieser Grenzen arbeiten können.' },
  tldr: { title: 'Wichtigste Erkenntnisse', isTldr: true, items: ['**Kontextfenster** = die maximale Anzahl von Tokens, die ein Modell auf einmal verarbeiten kann; sobald Sie es überschreiten, wird älterer Inhalt gekürzt oder zusammengefasst', '**Tokens ≈ 4 Zeichen** im Durchschnitt; ein 4k Kontextfenster ≈ 3.000 Wörter einfachen Text', 'Modelle "merken sich" vorherige Chats nicht — jede Interaktion startet neu innerhalb seines Kontextfensters', '**Kontextüberlastung erhöht Halluzinationen**, weil das Modell Lücken mit plausiblen Vermutungen füllt, wenn Originaldetails aus dem Blickfeld verschwinden', '**Prompt-Struktur ist wichtiger als Glück:** Platzieren Sie kritische Anweisungen vorne, vermeiden Sie Wiederholungen, fassen Sie lange Austausche zusammen, bevor Sie weitergehen', 'Für **lokale LLMs** benötigen größere Kontextfenster mehr VRAM — ein 128k Kontextmodell auf einem 7B Parameter-Modell kann 32GB+ RAM erfordern'] },
  whatIsContextWindow: { title: 'Was ist ein Kontextfenster?', content: ['**Ein Kontextfenster ist die maximale Menge an Text (gemessen in Tokens), die ein LLM berücksichtigen kann, wenn es seine nächste Ausgabe generiert.**', 'Stellen Sie sich das als den "sichtbaren Text" des Modells zu jedem gegebenen Moment vor. Wenn Sie eine Nachricht an GPT-4o mit einem 128k Token-Kontextfenster senden, kann das Modell die letzten 128.000 Tokens des Gesprächs "sehen" — ungefähr 96.000 Wörter. Alles davor ist für das Modell unsichtbar und beeinflusst seine Antwort nicht.', '**Tokens vs. Wörter:** Ein Token ist kein Wort. Im Durchschnitt entspricht ein Token ≈ 4 Zeichen oder etwa 0,75 Wörter. Ein 4.000-Token-Kontextfenster ≈ 3.000 Wörter einfachen englischen Text. Für dichten Code oder Sprachen wie Japanisch ist das Verhältnis anders — Japanischer Text benötigt aufgrund der Zeichenkodierung ungefähr 2 Tokens pro Wort.', '**Kontextfenstergröße variiert stark** zwischen Modellen:'], rows: [{ 'Modell': 'GPT-3.5 Turbo', 'Kontextfenster': '4k Tokens (≈ 3.000 Wörter)' }, { 'Modell': 'GPT-4 Turbo', 'Kontextfenster': '128k Tokens (≈ 96.000 Wörter)' }, { 'Modell': 'Claude 3.5 Sonnet', 'Kontextfenster': '200k Tokens (≈ 150.000 Wörter)' }, { 'Modell': 'Claude Opus 4.6 (März 2026)', 'Kontextfenster': '1.000.000 Tokens (≈ 750.000 Wörter — ganze Bücher in einem Kontext)' }, { 'Modell': 'Gemini 1.5 Pro', 'Kontextfenster': '1.000.000 Tokens' }, { 'Modell': 'Lokale Modelle (Ollama, LM Studio)', 'Kontextfenster': 'Konfigurierbar 4k bis 128k+, begrenzt durch verfügbaren RAM' }], tableFormat: true },
  contextWindowNote: { content: 'Das Prinzip ist bei allen Modellen identisch: Alles außerhalb des Fensters ist unsichtbar.' },
  whyForgets: { title: 'Warum "vergisst" KI', content: ['**Wenn die Gesamtzahl der Tokens in einer Konversation (System-Prompt + Chat-Verlauf + Benutzereingabe + Tools + erwartete Ausgabe) das Kontextfenster überschreitet, werden ältere Teile gekürzt, zusammengefasst oder ganz gelöscht.**', 'Das ist nicht Gedächtnisverlust wie menschliche Vergesstlichkeit. Das Modell "denkt nicht und vergisst dann." Es sieht den gekürzten Text buchstäblich nicht — er existiert nicht mehr im Input-Raum des Modells.', '**Häufige Symptome beim Erreichen des Kontextlimits:**'], items: ['Die KI ignoriert oder widerspricht einer Anweisung, die Sie vor 30 Nachrichten gegeben haben', 'In einer langen kreativen Geschichte vergisst das Modell Charakternamen, Details oder Einschränkungen, die Sie früher festgelegt haben', 'In einem Forschungs-Chat über viele Turns hinweg werden Fakten durcheinander gebracht oder das Modell erfindet Informationen neu', 'Die KI ändert plötzlich den Ton oder verletzt Ihre ursprünglichen Einschränkungen ohne Erklärung'], image: '/images/context-window-token-flow-de.svg', imageCaption: 'Kontextfenster funktionieren wie ein Schiebefenster: Neue Tokens drücken alte hinaus — sobald das Fenster voll ist, kann das Modell frühere Inhalte nicht mehr sehen.' },
  whatHappens: { title: 'Was passiert tatsächlich', content: 'Die meisten Chat-Interfaces verwenden eine dieser Strategien:', numberedItems: ['**Älteste Nachrichten löschen** — Die neuesten N Nachrichten passen ins Fenster; ältere werden ganz verworfen', '**Früheren Chat zusammenfassen** — Das System komprimiert frühe Nachrichten in eine kurze Zusammenfassung ("Früher haben Sie X, Y, Z… besprochen") um Kontext zu bewahren', '**System-/Entwickler-Prompts fixieren** — Die System-Nachricht bleibt fest, während Benutzernachrichten rotieren'] },
  whatHappensNote: { content: 'All diese Methoden bewahren den "Kern", verlieren aber spezifische Details. Wenn das Modell die ursprüngliche Anweisung nicht mehr sieht, kann es sie nicht befolgen.' },
  hallucinations: { title: 'Kontextfenster und Halluzinationen', content: ['**Kontextüberlastung verstärkt Halluzinationen, weil das Modell Lücken mit plausiblen Vermutungen füllt, wenn die Originalinformation nicht mehr sichtbar ist.**', 'So sieht das Muster aus: Sie bitten die KI, etwas zu referenzieren, das Sie vor 50 Nachrichten erwähnt haben. Diese Nachricht ist aber aus dem Kontextfenster rotiert. Das Modell hat keinen Zugang zur tatsächlichen Tatsache, also generiert es eine plausibel klingende Antwort basierend auf dem, was es aus dem aktuellen Kontext ableitet. Ergebnis: Erfindung.', 'Daher produzieren hoch-kontextuelle, lange Chats oft mehr Halluzinationen als fokussierte, kurze Austausche. Das Modell verliert nicht seine Argumentationsfähigkeit — es arbeitet mit unvollständiger Information.', '**Die Beziehung ist direkt:** Weniger Kontext → fehlende Verankerung → erhöhtes Halluzinationsrisiko.', 'Dieser Effekt verstärkt sich mit höheren Temperature und Top-P Einstellungen, die bereits Zufälligkeit erhöhen. Siehe [Fundamentals: Temperature and Top-P: Control AI Creativity] um zu verstehen, wie Parameteroptimierung mit Halluzination interagiert.'] },
  promptDesign: { title: 'Wie Prompt-Design hilft, im Fenster zu bleiben', content: '**Strategisches Strukturieren Ihrer Prompts ermöglicht es, mehr innerhalb eines festen Kontext-Budgets zu erreichen.**', image: '/images/context-window-prompt-strategies-de.svg', imageCaption: 'Prompt-Trimming spart 30–50% Tokens: Entfernen redundanter Kontexte aus früheren Turns hält das Fenster fokussiert auf das, was das Modell wissen muss.' },
  promptDesignStrategies: { content: ['**Kritische Anweisungen vorne platzieren.** Platzieren Sie Ihre wichtigsten Einschränkungen, Regeln und Definitionen im System-Prompt oder in der allerersten Benutzernachricht. Diese werden weniger aus dem Kontext fallen als Anweisungen, die 20 Turns später vergraben sind.', '**Wiederholungen vermeiden.** Wenn Sie etwas bereits einmal erklärt haben, kopieren Sie es nicht erneut ein. Referenzieren Sie es stattdessen: "Wie wir in der obigen Zusammenfassung besprochen haben…" Das spart Tokens.', '**Zusammenfassung explizit machen.** Bitten Sie das Modell, die bisherigen wichtigsten Entscheidungen, Einschränkungen oder Fakten zusammenzufassen. Bauen Sie dann die nächste Antwort auf dieser Zusammenfassung auf, anstatt sich auf verstreute frühere Kontexte zu verlassen.', '**Turns fokussiert halten.** Ein langer, mehrteiliger Monolog nutzt den Kontext ineffizient. Teilen Sie ihn in separate, eng begrenzte Austausche auf.'] },
  contextTable: { title: 'Kontext-Fenster-Größen (2026)', rows: [{ 'Gewohnheit': 'Wiederholung von langem Kontext bei jedem Turn', 'Kontext-Auswirkung': '🔴 Hoher Verschleiß' }, { 'Gewohnheit': 'Anweisungen im System-Prompt vorne platzieren', 'Kontext-Auswirkung': '🟢 Effizient' }, { 'Gewohnheit': 'Explizite Zusammenfassungen vor Fortschritt verlangen', 'Kontext-Auswirkung': '🟢 Erhält Fokus' }, { 'Gewohnheit': 'Frühere Punkte referenzieren statt erneut einfügen', 'Kontext-Auswirkung': '🟢 Spart Tokens' }, { 'Gewohnheit': 'Ein Monolog mit 5 unverbundenen Fragen', 'Kontext-Auswirkung': '🔴 Verwirrt den Fokus' }, { 'Gewohnheit': '5 separate, fokussierte Austausche', 'Kontext-Auswirkung': '🟢 Klar, effizient' }], tableFormat: true, image: '/images/context-window-size-comparison-de.svg', imageCaption: 'Kontextfenster-Größen 2026: Gemini unterstützt 1M Tokens (8× Claude, 32× Mistral) — der Unterschied bestimmt, ob eine ganze Codebase in eine Anfrage passt.' },
  longDocuments: { title: 'Arbeiten mit langen Dokumenten', content: ['**Das Einfügen ganzer Bücher oder hundertseiten-langer PDFs in ein einzelnes Kontextfenster ist ineffizient, auch für Claude Opus\'s 1M Token-Fenster, weil das Modell nicht effektiv über mehrere unterschiedliche Abschnitte hinweg fokussieren kann.**', 'Ein 1.000-Seiten-Buch ≈ 250.000 Tokens. Technisch kann Claude Opus es aufnehmen. Praktisch verschlechtert sich die Argumentationsfähigkeit des Modells, wenn es aufgefordert wird, Fragen über stark unterschiedliche Abschnitte zu beantworten — wie wenn man eine Person auffordert, einen ganzen Roman in einem Sitzen zu lesen und dann spezifische Details von Seite 50, 200 und 400 zu erinnern. Die Erinnerung wird vage.', '**Bessere Ansätze für lange Dokumente:**'], numberedItems: ['**Abschnitte sequenziell verarbeiten.** Extrahieren und analysieren Sie ein Kapitel oder einen Abschnitt auf einmal. Stellen Sie fokussierte Fragen pro Abschnitt: "Was sind die Hauptschlussfolgerungen in Abschnitt 3?" Dann gehen Sie zum nächsten Abschnitt über.', '**Hierarchische Zusammenfassung.** Extrahieren Sie Schlüsselpunkte aus Seiten 1–10, dann Seiten 11–20, kombinieren Sie diese Zusammenfassungen dann in eine Kapitel-Zusammenfassung. Kombinieren Sie dann Kapitel in eine Dokument-Zusammenfassung. Dies reduziert das Dokument auf seine wesentlichen Fakten, bewahrt aber Beziehungen.', '**Strukturierte Extraktion.** Konvertieren Sie das Dokument in Tabellen, JSON oder Bullet-Listen, *bevor* Sie Fragen auf höherer Ebene stellen. Das komprimiert die Information: Statt 50 Seiten Produktspezifikationen einzufügen, extrahieren Sie die Spezifikationen in eine strukturierte Tabelle, stellen Sie dann Fragen zur Tabelle.', '**Verwenden Sie RAG (Retrieval-Augmented Generation).** Für wirklich große Dokumentenmengen (100+ Seiten) funktionieren abrufbasierte Systeme besser. Siehe [Techniques: RAG Explained: How to Ground AI Answers in Real Data] wie Sie relevante Abschnitte abrufen statt alles auf einmal zu laden.'] },
  promptQuorumContext: { title: 'Wie PromptQuorum Ihnen hilft, Kontext zu verwalten', content: 'Aus meiner Erfahrung beim Aufbau von PromptQuorum habe ich festgestellt, dass die Arbeit nahe an Kontextlimits knifflig ist, weil jedes Modell unterschiedliche Limits, Kürzungsverhalten, Preisgestaltung und (für lokale LLMs) RAM-Anforderungen hat. PromptQuorum hilft Ihnen, das transparent und absichtlich zu machen.' },
  contextWindowAdjustment: { title: 'Kontextfenster-Anpassung für lokale LLMs', content: ['Wenn Sie ein Modell in LM Studio oder Ollama ausführen, können Sie die Kontextfenstergröße konfigurieren. Standardmäßig stellen Werkzeuge es auf das Maximum des Modells (z.B. 32k für ein 7B-Modell). Aber das ist selten das, was Sie brauchen.', 'PromptQuorum integriert sich mit LM Studio und ermöglicht es Ihnen, das Kontextfenster pro Aufgabe anzupassen: wählen Sie 4k für leichte, schnelle Q&A; wählen Sie 32k für tiefe Dokumentanalyse; wählen Sie 64k für lange Gespräche. Das macht den Trade-off explizit statt in Config-Dateien versteckt.'] },
  contextOverflowChecks: { title: 'Automatische Kontextüberfluss-Checks', content: ['PromptQuorum prüft *bevor* Sie senden: Wenn Ihr System-Prompt + aktueller Chat-Verlauf + Ihre neue Eingabe + erwartete Ausgabelänge gegeben sind, passt das in das konfigurierte Kontextfenster für jedes Modell?', 'Wenn Überfluss wahrscheinlich ist, warnt PromptQuorum Sie oder fordert Sie auf, den Chat zu trimmen/zusammenzufassen, bevor Sie senden. Keine Überraschung durch Kürzung mehr. Keine Rätsel darüber, warum die KI "vergessen hat."'] },
  vramTradeoff: { title: 'Kontextfenster ↔ RAM Trade-off', content: ['Für lokale Modelle benötigen größere Kontextfenster exponentiell mehr RAM. Ein 7B Parameter-Modell mit 4k Kontextfenster benötigt ~14GB RAM. Das gleiche Modell mit 128k Kontextfenster benötigt 32GB+. Gehen Sie weiter und die GPU läuft aus RAM, stürzt ab oder fällt auf CPU-Inferenz zurück (was 10–100× langsamer ist).', 'PromptQuorum zeigt Ihnen diese Beziehung: "Dieses Kontextfenstergröße wird ~28GB RAM auf Ihrer Hardware verwenden. Sie haben 16GB verfügbar." Sie können dann das Kontextfenster für Ihre Aufgabe und Hardware richtig dimensionieren, statt Abstürze während der Inferenz zu entdecken.'] },
  multiModelAwareness: { title: 'Multi-Modell-Bewusstsein', content: 'Wenn Sie einen Prompt an GPT-4o (128k Fenster), Claude (200k Fenster) und ein lokales 7B-Modell (Ihr gewähltes 32k Fenster) versenden, behält PromptQuorum Ihren Prompt automatisch innerhalb aller drei Grenzen. Ein Prompt, mehrere Modelle, kein manuelles Umschreiben.' },
  recipes: { title: 'Praktische Rezepte für Kontextverwaltung' },
  recipe1: { title: 'Rezept 1: Langer Chat über ein Projekt', content: '**Ziel:** Ein Multi-Turn-Gespräch über ein einzelnes Projekt führen, ohne frühere Entscheidungen zu verlieren.', numberedItems: ['Betten Sie in Ihren System-Prompt die Schlüsselbeschränkungen des Projekts (Umfang, Zielgruppe, Ton, technische Limits) einmal ein. Wiederholen Sie sie nicht.', 'Nach jedem 10–15 Austausch bitten Sie das Modell, den aktuellen Status zusammenzufassen: "Was sind die 5 wichtigsten Entscheidungen, die wir bisher getroffen haben?"', 'Verwenden Sie diese Zusammenfassung als Kontext Ihres nächsten Turns, statt sich auf verstreute frühere Nachrichten zu verlassen.', 'In PromptQuorum stellen Sie ein Kontextfenster von 32k–64k ein und aktivieren Überfluss-Warnungen, damit Sie wissen, wann Sie zusammenfassen sollten.'] },
  recipe2: { title: 'Rezept 2: Analyse eines langen Berichts', content: '**Ziel:** Erkenntnisse aus einem 50–100-Seiten-Dokument extrahieren.', numberedItems: ['Teilen Sie das Dokument in 3–5 Abschnitte (Kapitel, Teile).', 'Für jeden Abschnitt schreiben Sie einen fokussierten Prompt: "Fassen Sie die Schlüsselergebnisse dieses Abschnitts in 5 Bullet Points zusammen."', 'Sammeln Sie diese 5 Zusammenfassungen von jedem Abschnitt.', 'In einem letzten Turn fragen Sie: "Angesichts dieser Abschnittszusammenfassungen, was ist die Gesamtschlussfolgerung?"', 'Sie sind gut innerhalb der Kontextlimits geblieben und haben das "im Buch verloren" Problem vermieden.'] },
  recipe3: { title: 'Rezept 3: Prompting am Rande des Kontextfensters', content: '**Ziel:** Das fast vollständige Kontextfenster ohne Überfluss verwenden.', numberedItems: ['Berechnen Sie Ihr Budget: Kontextfenstergröße − System-Prompt-Tokens − erwartete Ausgabe-Tokens = verfügbare Tokens für Ihre Eingabe + Verlauf.', 'Beispiel: 128k Fenster, 200-Token System-Prompt, 1k Ausgabe-Puffer = 126,8k verfügbare Tokens.', 'Bevor Sie senden, überprüfen Sie in PromptQuorum: "Wie viele Tokens verbraucht diese Eingabe?"', 'Wenn nah am Limit, trimmen Sie den ältesten Turn oder fassen Sie ihn zusammen, bevor Sie fortfahren.', 'Dies hält Sie absichtlich nah am Limit betrieblich, nicht zufällig es zu erreichen.'] },
  recipe4: { title: 'Rezept 4: Lokales LLM mit begrenztem RAM', content: '**Ziel:** Ein lokales Modell effektiv ohne Abstürze ausführen.', numberedItems: ['Beginnen Sie mit einem konservativen Kontextfenster (8k–16k) für Ihres Modells RAM.', 'In PromptQuroums Einstellungen notieren Sie die RAM-Anforderung bei dieser Fenstergröße.', 'Führen Sie Ihre Aufgabe aus. Wenn Sie Überfluss haben, fassen Sie den Chat zusammen und starten Sie von der Zusammenfassung neu.', 'Wenn Sie sich dem Limit nie nähern, erhöhen Sie langsam das Kontextfenster und testen Sie erneut.', 'Finden Sie das "richtig dimensionierte" Kontextfenster Ihres Modells für Ihre Hardware und Aufgaben.'] },
  commonMistakes: { title: 'Häufige Fehler bei Kontextfenstern', items: ['"Das Modell merkt sich alle meine bisherigen Chats." Nein. Jedes neue Gespräch startet mit null Kontext aus früheren Chats. Sogar innerhalb eines Chats, sobald Ihr Austausch das Kontextfenster überschreitet, ist es weg.', '"Ich werde einfach den gleichen langen Kontext bei jedem Turn einfügen." Das verschwendet Tokens und hilft nicht — das Modell kann trotzdem nicht über 300 Seiten effektiv nachdenken. Fassen Sie stattdessen zusammen und referenzieren Sie die Zusammenfassung.', '"Ich werde fünf verschiedene Projekte in ein lange Gespräch mischen." Jedes Projekt konkurriert um Tokens. Wenn Kontext sich füllt, werden Details gekürzt. Verwenden Sie separate Chats pro Projekt.', '"Die KI ist schlecht beim Nachdenken — muss Temperature oder Top-P sein." Vielleicht. Aber zuerst kontrollieren Sie das Kontextfenster. Wenn das Modell die ursprüngliche Einschränkung nicht mehr sieht, ist das kein Parameter-Problem; es ist fehlende Information.', '"Ich werde das Kontextfenster auf meinem lokalen LLM maximieren." Dann läuft Ihnen der RAM aus, der Prozess stürzt ab und die Inferenz fällt auf langsamen CPU-Modus zurück. Stellen Sie stattdessen Kontext Ihrer Hardware ein.', '"Die App hat mich vor Überfluss gewarnt, aber ich habe es trotzdem gesendet." Vertrauen Sie der Warnung. Überfluss führt zu stiller Kürzung, versteckten Halluzinationen und verschwendeten Tokens. Fassen Sie erst zusammen.'] },
  faq: { title: 'FAQ', faqs: [{ q: 'Merkt sich das Modell meine bisherigen Chats?', a: 'Nein. Jede neue Chatsession startet mit null Verlauf. Das Modell sieht nur Tokens innerhalb des aktuellen Kontextfensters. Wenn Sie auf einen bisherigen Chat referenzieren möchten, müssen Sie relevante Teile in das aktuelle Gespräch kopieren.' }, { q: 'Warum hat die KI eine Anweisung ignoriert, die ich vor 20 Nachrichten gegeben habe?', a: 'Diese Anweisung ist wahrscheinlich aus dem Kontextfenster gefallen. Das Modell sieht sie nicht mehr, also kann es sie nicht befolgen. Lösung: Wiederholen Sie kritische Anweisungen in Ihrem System-Prompt oder bitten Sie das Modell, die Anweisung mitten im Gespräch zu rekapitulieren und erneut einzubetten.' }, { q: 'Ist ein größeres Kontextfenster immer besser?', a: 'Nein. Ein größeres Fenster ermöglicht es, mehr Inhalte einzufügen, aber es erhöht auch die Kosten (mehr Tokens zum Verarbeiten) und für lokale Modelle RAM-Nutzung. Wählen Sie ein Kontextfenster, das zu Ihrer Aufgabe passt: 4k für einfache Q&A, 32k für lange Gespräche, 128k+ für Dokumentanalyse. Größer ist nicht "besser" — *angemessen* ist besser.' }, { q: 'Wie weiß ich, wann ich das Kontextlimit erreicht habe?', a: 'Die Antworten des Modells ändern den Ton, widersprechen früheren Anweisungen oder verlieren den Überblick über Details, die Sie früher festgelegt haben. Verwenden Sie PromptQuroums Kontextüberfluss-Check vor dem Senden — er warnt Sie, wenn Sie sich dem Limit nähern.' }, { q: 'Wie beeinflusst die Kontextfenstergröße die RAM-Nutzung für lokale Modelle?', a: 'Größere Kontextfenster verwenden ungefähr proportional mehr RAM: Das Verdoppeln des Kontextfensters verdoppelt ungefähr die RAM-Nutzung. Ein 7B-Modell bei 4k Kontext ≈ 14GB RAM; bei 32k Kontext ≈ 28GB RAM. Überprüfen Sie PromptQuroums RAM-Rechner, um Ihres Hardware-Decke zu kennen.' }, { q: 'Können Werkzeuge wie PromptQuorum Kontextüberfluss verhindern?', a: 'Ja. PromptQuorum prüft Ihren Prompt-Token-Zähler, Ihr konfiguriertes Kontextfenster und das tatsächliche Limit Ihres Modells, warnt Sie dann vor dem Senden, wenn Überfluss wahrscheinlich ist. Sie können dann vor dem Fortfahren trimmen oder zusammenfassen.' }, { q: 'Gehen verschiedene Modelle mit langem Kontext unterschiedlich um?', a: 'Ja. Claude 3.5 Sonnet behält den Fokus über 200k Tokens gut. GPT-4o ist solid bei 128k. Kleinere Modelle (z.B. LLaMA 2 7B) verlieren manchmal die Argumentationslogik über 8k–16k hinaus, sogar wenn ihr Kontextfenster technisch größer ist. Der sicherste Ansatz: Testen Sie Ihr spezifisches Modell und Ihre Aufgabe.' }] },
  relatedReading: { title: 'Verwandte Lektüre', items: ['[Fundamentals: The 5 Building Blocks Every Prompt Needs] — wie man Prompts strukturiert, bevor Kontext zum Constraint wird', '[Fundamentals: AI Hallucinations: Why AI Makes Things Up] — warum fehlender Kontext Halluzinationsrisiko erhöht', '[Techniques: RAG Explained: How to Ground AI Answers in Real Data] — wie man wirklich große Dokumentenmengen mit Abruf statt Rohkontext handhabt'] },
  sources: { title: 'Quellen', items: ['[OpenAI, 2024. "API reference: Models and context windows"](https://platform.openai.com/docs/models) — offizielle Dokumentation zu Token-Limits und Preisgestaltung pro Modell', '[Anthropic, 2024. "Claude model context windows and token costs"](https://docs.anthropic.com/en/docs/about-claude/models/overview) — Claudes 200k Kontextfenster und März 2026 Opus 4.6 1M Kontext-Ankündigung', '[Raffel et al., 2020. "Exploring the Limits of Transfer Learning with a Unified Text-to-Text Transformer"](https://arxiv.org/abs/1910.10683) — Grundlagenforschung zu Kontextfenstereffekten in Transformers'] },
}

export const contextWindowsFr: Record<string, PESection> = {
  definition: { title: 'Fenêtres de contexte expliquées : Pourquoi l\'IA oublie', content: '**Les LLM n\'ont pas de mémoire à long terme — ils ne "voient" qu\'une fenêtre glissante de tokens récents, et tout ce qui se trouve en dehors de cette fenêtre est oublié ou comprimé.** Cet article explique ce que cela signifie pour vos prompts et comment fonctionner à l\'intérieur (et autour de) ces limites.' },
  tldr: { title: 'Points clés à retenir', isTldr: true, items: ['**Fenêtre de contexte** = le nombre maximal de tokens qu\'un modèle peut traiter à la fois ; une fois que vous le dépassez, le contenu plus ancien est tronqué ou résumé', '**Tokens ≈ 4 caractères** en moyenne ; une fenêtre de contexte de 4k ≈ 3 000 mots de texte brut', 'Les modèles ne "se souviennent" pas des chats précédents — chaque interaction recommence à zéro dans sa fenêtre de contexte', '**La surcharge de contexte augmente les hallucinations** car le modèle comble les lacunes par des suppositions plausibles lorsque les détails originaux disparaissent de la vue', '**La structure des prompts est plus importante que la chance :** placez les instructions critiques en avant, évitez la répétition, résumez les longs échanges avant de progresser', 'Pour les **LLM locaux**, les fenêtres de contexte plus grandes exigent plus de RAM — un modèle de contexte 128k sur un modèle de 7B paramètres peut nécessiter 32 Go+ de RAM'] },
  whatIsContextWindow: { title: 'Qu\'est-ce qu\'une fenêtre de contexte ?', content: ['**Une fenêtre de contexte est la quantité maximale de texte (mesurée en tokens) qu\'un LLM peut prendre en compte lors de la génération de sa prochaine sortie.**', 'Pensez-y comme le "texte visible" du modèle à tout moment donné. Lorsque vous envoyez un message à GPT-4o avec une fenêtre de contexte de 128k tokens, le modèle peut "voir" les 128 000 derniers tokens de conversation — environ 96 000 mots. Tout ce qui précède est invisible pour le modèle et n\'influence pas sa réponse.', '**Tokens vs. mots :** Un token n\'est pas un mot. En moyenne, un token ≈ 4 caractères ou environ 0,75 mots. Une fenêtre de contexte de 4 000 tokens ≈ 3 000 mots de texte anglais brut. Pour le code dense ou les langues comme le japonais, le ratio est différent — le texte japonais nécessite environ 2 tokens par mot en raison de l\'encodage des caractères.', '**Les tailles de fenêtre de contexte varient considérablement** entre les modèles :'], rows: [{ 'Modèle': 'GPT-3.5 Turbo', 'Fenêtre de contexte': '4k tokens (≈ 3 000 mots)' }, { 'Modèle': 'GPT-4 Turbo', 'Fenêtre de contexte': '128k tokens (≈ 96 000 mots)' }, { 'Modèle': 'Claude 3.5 Sonnet', 'Fenêtre de contexte': '200k tokens (≈ 150 000 mots)' }, { 'Modèle': 'Claude Opus 4.6 (Mars 2026)', 'Fenêtre de contexte': '1 000 000 tokens (≈ 750 000 mots — des livres entiers en un contexte)' }, { 'Modèle': 'Gemini 1.5 Pro', 'Fenêtre de contexte': '1 000 000 tokens' }, { 'Modèle': 'Modèles locaux (Ollama, LM Studio)', 'Fenêtre de contexte': 'Configurable 4k à 128k+, limité par la RAM disponible' }], tableFormat: true },
  contextWindowNote: { content: 'Le principe est identique pour tous les modèles : tout ce qui se trouve en dehors de la fenêtre est invisible.' },
  whyForgets: { title: 'Pourquoi l\'IA "oublie"', content: ['**Quand le nombre total de tokens dans une conversation (invite système + historique de chat + entrée utilisateur + outils + sortie attendue) dépasse la fenêtre de contexte, les parties plus anciennes sont tronquées, résumées ou supprimées entièrement.**', 'Ce n\'est pas une perte de mémoire comme l\'oubli humain. Le modèle ne "pense pas puis oublie." Il ne voit tout simplement pas le texte tronqué — il n\'existe plus dans l\'espace d\'entrée du modèle.', '**Symptômes courants du dépassement de la limite de contexte :**'], items: ['L\'IA ignore ou contredit une instruction que vous avez donnée il y a 30 messages', 'Dans une longue histoire créative, le modèle oublie les noms de personnages, les détails ou les contraintes que vous avez établis plus tôt', 'Dans un chat de recherche sur plusieurs tours, les faits se mélangent ou le modèle réinvente l\'information', 'L\'IA change soudainement de ton ou viole vos contraintes d\'origine sans explication'] },
  whatHappens: { title: 'Ce qui se passe réellement', content: 'La plupart des interfaces de chat utilisent l\'une de ces stratégies :', numberedItems: ['**Supprimer les messages les plus anciens** — Les N messages les plus récents s\'adaptent à la fenêtre ; les plus anciens sont entièrement supprimés', '**Résumer la conversation antérieure** — Le système comprime les premiers messages en un bref résumé ("Précédemment, vous avez discuté X, Y, Z…") pour préserver le contexte', '**Épingler les prompts système/développeur** — Le message système reste fixe tandis que les messages utilisateur tournent'] },
  whatHappensNote: { content: 'Toutes ces méthodes préservent "l\'essentiel" mais perdent des détails spécifiques. Quand le modèle ne voit plus l\'instruction originale, il ne peut pas la suivre.' },
  hallucinations: { title: 'Fenêtres de contexte et hallucinations', content: ['**La surcharge de contexte amplifie les hallucinations car le modèle comble les lacunes par des suppositions plausibles quand l\'information originale n\'est plus visible.**', 'Voici le schéma : Vous demandez à l\'IA de se référer à quelque chose que vous avez mentionné il y a 50 messages. Mais ce message a basculé hors de la fenêtre de contexte. Le modèle n\'a pas accès au fait réel, il génère donc une réponse qui semble plausible basée sur ce qu\'il déduit du contexte actuel. Résultat : fabrication.', 'C\'est pourquoi les chats longs et contextuels produisent souvent plus d\'hallucinations que les échanges courts et focalisés. Le modèle ne perd pas sa capacité de raisonnement — il travaille avec des informations incomplètes.', '**L\'interaction est directe :** Moins de contexte → manque d\'ancrage → risque accru d\'hallucination.', 'Cet effet se renforce avec des paramètres de température et top-p plus élevés, qui augmentent déjà l\'aléatoire. Voir [Fundamentals: Temperature and Top-P: Control AI Creativity] pour comprendre comment l\'ajustement des paramètres interagit avec l\'hallucination.'] },
  promptDesign: { title: 'Comment la conception de prompts vous aide à rester dans la fenêtre', content: '**Structurer vos prompts stratégiquement vous permet d\'en accomplir plus dans un budget de contexte fixe.**', image: '/images/context-window-prompt-strategies-fr.svg', imageCaption: 'Optimisation prompt économise 30–50% de tokens : supprimer le contexte redondant des tours antérieurs garde la fenêtre focalisée sur ce que le modèle doit savoir.' },
  promptDesignStrategies: { content: ['**Placer les instructions critiques en avant.** Placez vos contraintes, règles et définitions les plus importantes dans l\'invite système ou le tout premier message utilisateur. Elles sont moins susceptibles de sortir du contexte que les instructions enfouies 20 tours plus tard.', '**Éviter la répétition.** Si vous avez déjà expliqué quelque chose une fois, ne le collez pas à nouveau. À la place, référencez-le : "Comme nous l\'avons discuté dans le résumé ci-dessus…" Cela économise des tokens.', '**Récapituler explicitement.** Demandez au modèle de résumer les décisions, contraintes ou faits clés jusqu\'à présent. Construisez ensuite la réponse suivante sur ce résumé au lieu de vous fier à un contexte antérieur dispersé.', '**Garder les tours focalisés.** Un long monologue multi-sujets utilise le contexte inefficacement. Divisez-le en échanges séparés et étroitement ciblés.'] },
  contextTable: { title: 'Tailles Fenêtre Contextuelle (2026)', rows: [{ 'Habitude': 'Répéter le long contexte à chaque tour', 'Impact sur le contexte': '🔴 Gaspillage élevé' }, { 'Habitude': 'Placer les instructions en avant dans l\'invite système', 'Impact sur le contexte': '🟢 Efficace' }, { 'Habitude': 'Demander des résumés explicites avant de continuer', 'Impact sur le contexte': '🟢 Préserve la focalisation' }, { 'Habitude': 'Référencer les points antérieurs au lieu de les recoller', 'Impact sur le contexte': '🟢 Économise les tokens' }, { 'Habitude': 'Monologue unique avec 5 questions non liées', 'Impact sur le contexte': '🔴 Confond la focalisation' }, { 'Habitude': '5 échanges séparés et focalisés', 'Impact sur le contexte': '🟢 Clair, efficace' }], tableFormat: true, image: '/images/context-window-size-comparison-fr.svg', imageCaption: 'Tailles fenêtre contexte 2026 : Gemini supporte 1M de tokens (8× Claude, 32× Mistral) — la différence détermine si une codebase entière tient dans une requête.' },
  longDocuments: { title: 'Travailler avec de longs documents', content: ['**Coller des livres entiers ou des PDF de centaines de pages dans une seule fenêtre de contexte est inefficace, même pour la fenêtre de 1M tokens de Claude Opus, car le modèle ne peut pas se concentrer efficacement sur plusieurs sections disparates simultanément.**', 'Un livre de 1 000 pages ≈ 250 000 tokens. Techniquement, Claude Opus peut l\'ingérer. En pratique, le raisonnement du modèle se dégrade quand on lui demande de répondre à des questions à travers des sections très différentes — c\'est comme demander à une personne de lire un roman entier en une seule séance, puis de se rappeler des détails spécifiques de la page 50, 200 et 400. Le souvenir devient flou.', '**Meilleures approches pour les longs documents :**'], numberedItems: ['**Traiter les sections séquentiellement.** Extrayez et analysez un chapitre ou une section à la fois. Posez des questions focalisées par section : "Quelles sont les conclusions principales de la section 3 ?" Passez ensuite à la section suivante.', '**Résumé hiérarchique.** Extrayez les points clés des pages 1–10, puis des pages 11–20, puis combinez ces résumés en un résumé au niveau du chapitre. Ensuite, combinez les chapitres en un résumé au niveau du document. Cela réduit le document à ses faits essentiels tout en préservant les relations.', '**Extraction structurée.** Convertissez le document en tableaux, JSON ou listes à puces *avant* de poser des questions de niveau supérieur. Cela comprime l\'information : au lieu de coller 50 pages de spécifications de produit, extrayez les spécifications dans un tableau structuré, posez ensuite des questions sur le tableau.', '**Utilisez RAG (Retrieval-Augmented Generation).** Pour des ensembles de documents vraiment volumineux (100+ pages), les systèmes basés sur la récupération fonctionnent mieux. Voir [Techniques: RAG Explained: How to Ground AI Answers in Real Data] pour récupérer les sections pertinentes au lieu de tout charger à la fois.'] },
  promptQuorumContext: { title: 'Comment PromptQuorum vous aide à gérer le contexte', content: 'À partir de mon expérience en construisant PromptQuorum, j\'ai trouvé que travailler près des limites de contexte est délicat parce que chaque modèle a des limites différentes, un comportement de troncature, une tarification et des exigences de RAM (pour les LLM locaux). PromptQuorum vous aide à rendre cela transparent et intentionnel.' },
  contextWindowAdjustment: { title: 'Ajustement de la fenêtre de contexte pour les LLM locaux', content: ['Quand vous exécutez un modèle dans LM Studio ou Ollama, vous pouvez configurer la taille de la fenêtre de contexte. Par défaut, les outils la définissent souvent au maximum du modèle (par ex. 32k pour un modèle 7B). Mais c\'est rarement ce dont vous avez besoin.', 'PromptQuorum s\'intègre avec LM Studio et vous permet d\'ajuster la fenêtre de contexte par tâche : choisissez 4k pour Q&A légers et rapides ; choisissez 32k pour l\'analyse approfondie de documents ; choisissez 64k pour les longues conversations. Cela rend l\'échange explicite au lieu de l\'être caché dans les fichiers de configuration.'] },
  contextOverflowChecks: { title: 'Vérifications automatiques du débordement de contexte', content: ['PromptQuorum vérifie *avant* que vous n\'envoyiez : Compte tenu de l\'invite système + historique de conversation actuel + votre nouvelle entrée + longueur de sortie attendue, cela s\'adaptera-t-il à la fenêtre de contexte configurée pour chaque modèle ?', 'Si le débordement est probable, PromptQuorum vous avertit ou vous demande de rogner/résumer la conversation avant d\'envoyer. Plus de troncature surprise. Plus de devinettes sur pourquoi l\'IA "a oublié."'] },
  vramTradeoff: { title: 'Fenêtre de contexte ↔ Échange de RAM', content: ['Pour les modèles locaux, les fenêtres de contexte plus grandes exigent exponentiellement plus de RAM. Un modèle de paramètres 7B avec une fenêtre de contexte de 4k a besoin d\'environ 14 Go de RAM. Le même modèle avec une fenêtre de contexte de 128k a besoin de 32 Go+. Allez plus loin et le GPU manque de mémoire, plante ou revient à l\'inférence CPU (ce qui est 10–100× plus lent).', 'PromptQuorum vous montre cette relation : "Cette taille de fenêtre de contexte utilisera environ 28 Go de RAM sur votre matériel. Vous avez 16 Go disponibles." Vous pouvez alors dimensionner correctement la fenêtre de contexte pour votre tâche et votre matériel au lieu de découvrir des plantages en cours d\'inférence.'] },
  multiModelAwareness: { title: 'Conscience multi-modèle', content: 'Quand vous envoyez un prompt à GPT-4o (fenêtre 128k), Claude (fenêtre 200k) et un modèle 7B local (votre fenêtre choisie 32k), PromptQuorum maintient automatiquement votre prompt dans les trois limites. Un prompt, plusieurs modèles, sans réécriture manuelle.' },
  recipes: { title: 'Recettes pratiques pour la gestion du contexte' },
  recipe1: { title: 'Recette 1 : Chat long sur un projet', content: '**Objectif :** Maintenir une conversation multi-tours sur un seul projet sans perdre les décisions antérieures.', numberedItems: ['Dans votre invite système, intégrez les contraintes clés du projet (portée, audience, ton, limites techniques) une fois. Ne les répétez pas.', 'Après chaque 10–15 échanges, demandez au modèle de résumer l\'état actuel : "Quelles sont les 5 décisions les plus importantes que nous avons prises jusqu\'à présent ?"', 'Utilisez ce résumé comme contexte de votre tour suivant au lieu de vous fier à des messages antérieurs dispersés.', 'Dans PromptQuorum, définissez une fenêtre de contexte de 32k–64k et activez les avertissements de débordement pour savoir quand résumer.'] },
  recipe2: { title: 'Recette 2 : Analyse d\'un long rapport', content: '**Objectif :** Extraire des informations d\'un document de 50–100 pages.', numberedItems: ['Divisez le document en 3–5 sections (chapitres, parties).', 'Pour chaque section, écrivez un prompt focalisé : "Résumez les conclusions clés de cette section en 5 points de balle."', 'Collectez ces 5 résumés de chaque section.', 'Dans un tour final, demandez : "Compte tenu de ces résumés de section, quelle est la conclusion générale ?"', 'Vous êtes resté bien dans les limites de contexte et avez évité le problème "perdu dans un livre".'] },
  recipe3: { title: 'Recette 3 : Prompting à la limite de la fenêtre de contexte', content: '**Objectif :** Utiliser presque la fenêtre de contexte complète sans débordement.', numberedItems: ['Calculez votre budget : Taille de fenêtre de contexte − tokens d\'invite système − tokens de sortie attendus = tokens disponibles pour votre entrée + historique.', 'Exemple : fenêtre 128k, invite système 200-tokens, tampon de sortie 1k = 126,8k tokens disponibles.', 'Avant d\'envoyer, vérifiez dans PromptQuorum : "Combien de tokens cette entrée prend-elle ?"', 'Si proche de la limite, rogner le tour le plus ancien ou le résumer avant de continuer.', 'Cela vous maintient fonctionnant intentionnellement près de la limite, pas aléatoirement la frapper.'] },
  recipe4: { title: 'Recette 4 : LLM local avec RAM limité', content: '**Objectif :** Exécuter un modèle local efficacement sans plantages.', numberedItems: ['Commencez par une fenêtre de contexte conservatrice (8k–16k) pour la RAM de votre modèle.', 'Dans les paramètres de PromptQuorum, notez l\'exigence RAM à cette taille de fenêtre.', 'Exécutez votre tâche. Si vous avez un débordement, résumez la conversation et redémarrez à partir du résumé.', 'Si vous ne vous rapprochez jamais de la limite, augmentez lentement la fenêtre de contexte et testez à nouveau.', 'Trouvez la fenêtre de contexte "dimensionnée correctement" de votre modèle pour votre matériel et vos tâches.'] },
  commonMistakes: { title: 'Erreurs courantes avec les fenêtres de contexte', items: ['"Le modèle se souvient de tous mes chats précédents." Ce n\'est pas le cas. Chaque nouvelle conversation commence avec zéro contexte des chats antérieurs. Même dans un chat, une fois que votre échange dépasse la fenêtre de contexte, c\'est parti.', '"Je vais juste coller le même long contexte à chaque tour." Cela gaspille des tokens et n\'aide pas — le modèle ne peut toujours pas raisonner efficacement sur 300 pages. À la place, résumez et référencez le résumé.', '"Je vais mélanger cinq projets différents en une longue conversation." Chaque projet concurrence les tokens. Quand le contexte se remplit, les détails sont tronqués. Utilisez des conversations séparées par projet.', '"L\'IA est mauvaise au raisonnement — doit être température ou top-p." Peut-être. Mais d\'abord, vérifiez la fenêtre de contexte. Si le modèle ne voit plus la contrainte originale, ce n\'est pas un problème de paramètre ; c\'est une information manquante.', '"Je vais maximiser la fenêtre de contexte sur mon LLM local." Puis vous manquez de RAM, le processus plante et l\'inférence revient au mode CPU lent. Définissez plutôt le contexte pour correspondre à votre matériel.', '"L\'application m\'a averti du débordement, mais j\'ai quand même envoyé." Faites confiance à l\'avertissement. Le débordement entraîne une troncature silencieuse, des hallucinations cachées et des tokens gaspillés. Résumez d\'abord.'] },
  faq: { title: 'FAQ', faqs: [{ q: 'Le modèle se souvient-il de mes chats précédents ?', a: 'Non. Chaque nouvelle session de conversation commence avec zéro historique. Le modèle ne voit que des tokens dans la fenêtre de contexte actuelle. Si vous voulez faire référence à un chat précédent, vous devez copier les parties pertinentes dans la conversation actuelle.' }, { q: 'Pourquoi l\'IA a-t-elle ignoré une instruction que j\'ai donnée il y a 20 messages ?', a: 'Cette instruction a probablement glissé hors de la fenêtre de contexte. Le modèle ne la voit plus, il ne peut donc pas la suivre. Solution : Répétez les instructions critiques dans votre invite système ou demandez au modèle de récapituler et de réintégrer l\'instruction en cours de conversation.' }, { q: 'Une fenêtre de contexte plus grande est-elle toujours mieux ?', a: 'Non. Une fenêtre plus grande vous permet d\'inclure plus de contenu, mais elle augmente également les coûts (plus de tokens à traiter) et, pour les modèles locaux, l\'utilisation de RAM. Choisissez une fenêtre de contexte adaptée à votre tâche : 4k pour Q&A simple, 32k pour les longues conversations, 128k+ pour l\'analyse de documents. Plus grand n\'est pas "mieux" — *approprié* est mieux.' }, { q: 'Comment savoir quand j\'ai atteint la limite de contexte ?', a: 'Les réponses du modèle changent de ton, contredisent les instructions antérieures ou perdent la trace des détails que vous avez définis plus tôt. Utilisez la vérification du débordement de contexte de PromptQuorum avant d\'envoyer — elle vous avertit si vous vous approchez de la limite.' }, { q: 'Comment la taille de la fenêtre de contexte affecte-t-elle la RAM pour les modèles locaux ?', a: 'Les fenêtres de contexte plus grandes utilisent plus de RAM grossièrement proportionnellement : doubler la fenêtre de contexte double grossièrement l\'utilisation de RAM. Un modèle 7B au contexte 4k ≈ 14 Go de RAM ; au contexte 32k ≈ 28 Go de RAM. Vérifiez la calculatrice RAM de PromptQuorum pour connaître le plafond de votre matériel.' }, { q: 'Les outils comme PromptQuorum peuvent-ils prévenir le débordement de contexte ?', a: 'Oui. PromptQuorum vérifie le nombre de tokens de votre prompt, votre fenêtre de contexte configurée et la limite réelle de votre modèle, puis vous avertit avant d\'envoyer si le débordement est probable. Vous pouvez ensuite rogner ou résumer avant de continuer.' }, { q: 'Les différents modèles gèrent-ils le contexte long différemment ?', a: 'Oui. Claude 3.5 Sonnet maintient bien la focalisation sur 200k tokens. GPT-4o est solide à 128k. Les modèles plus petits (par ex. LLaMA 2 7B) perdent parfois la cohérence du raisonnement au-delà de 8k–16k, même si leur fenêtre de contexte est techniquement plus grande. L\'approche la plus sûre : testez votre modèle spécifique et votre tâche.' }] },
  relatedReading: { title: 'Lectures connexes', items: ['[Fundamentals: The 5 Building Blocks Every Prompt Needs] — comment structurer les prompts avant que le contexte ne devienne une contrainte', '[Fundamentals: AI Hallucinations: Why AI Makes Things Up] — pourquoi le contexte manquant augmente le risque d\'hallucination', '[Techniques: RAG Explained: How to Ground AI Answers in Real Data] — comment gérer les très grands ensembles de documents avec la récupération au lieu du contexte brut'] },
  sources: { title: 'Sources', items: ['[OpenAI, 2024. "API reference: Models and context windows"](https://platform.openai.com/docs/models) — documentation officielle sur les limites de tokens et la tarification par modèle', '[Anthropic, 2024. "Claude model context windows and token costs"](https://docs.anthropic.com/en/docs/about-claude/models/overview) — fenêtre de contexte de Claude 200k et annonce de contexte Opus 4.6 1M de mars 2026', '[Raffel et al., 2020. "Exploring the Limits of Transfer Learning with a Unified Text-to-Text Transformer"](https://arxiv.org/abs/1910.10683) — recherche fondamentale sur les effets de fenêtre de contexte dans les transformers'] },
}

export const contextWindowsJa: Record<string, PESection> = {
  definition: { title: 'コンテキストウィンドウの説明：AIが忘れる理由', content: '**LLMは長期記憶を持たず、最近のトークンのスライディングウィンドウのみを「見て」おり、このウィンドウの外のすべてが忘れられるか圧縮されます。** この記事は、それがプロンプトにとって何を意味するのか、そしてこれらの制限の内側（および外側）でどのように機能するかを説明しています。' },
  tldr: { title: '重要なポイント', isTldr: true, items: ['**コンテキストウィンドウ** = モデルが一度に処理できる最大トークン数。超えるとコンテンツが古いほど切り詰められたり要約されたりします', '**トークン ≈ 4文字**（平均）。4kコンテキストウィンドウ ≈ プレーンテキスト3,000語', 'モデルは以前のチャットを「記憶」しません。各インタラクションはそのコンテキストウィンドウ内で新たに開始します', '**コンテキスト過負荷はハルシネーションを増加させます**。元の詳細がビューから消えるとき、モデルはもっともらしい推測でギャップを埋めるため', '**プロンプト構造は運より重要です。** 重要な指示を前に配置し、繰り返しを避け、前に進む前に長い交換をまとめてください', '**ローカルLLM**の場合、より大きなコンテキストウィンドウはより多くのVRAMを必要とします。7Bパラメータモデル上の128kコンテキストモデルは32GB以上のRAMが必要な場合があります'] },
  whatIsContextWindow: { title: 'コンテキストウィンドウとは何ですか?', content: ['**コンテキストウィンドウは、LLMが次の出力を生成するときに考慮に入れることができるテキストの最大量（トークンで測定）です。**', 'これをモデルの「見えるテキスト」をいつでも思い描いてください。GPT-4oに128kトークンのコンテキストウィンドウがある場合、モデルは会話の最後の128,000トークン（約96,000語）を「見る」ことができます。それより前のすべてはモデルに見えず、応答に影響しません。', '**トークンと単語：**トークンは単語ではありません。平均して、1トークン≈4文字または約0.75単語です。4,000トークンのコンテキストウィンドウ≈プレーンな英語テキスト3,000語です。密なコードまたは日本語などの言語の場合、比率は異なります。日本語テキストは文字エンコーディングのため、単語あたり約2トークンを必要とします。', '**コンテキストウィンドウのサイズはモデル間で大きく異なります：'], rows: [{ 'モデル': 'GPT-3.5 Turbo', 'コンテキストウィンドウ': '4k tokens (≈ 3,000語)' }, { 'モデル': 'GPT-4 Turbo', 'コンテキストウィンドウ': '128k tokens (≈ 96,000語)' }, { 'モデル': 'Claude 3.5 Sonnet', 'コンテキストウィンドウ': '200k tokens (≈ 150,000語)' }, { 'モデル': 'Claude Opus 4.6 (2026年3月)', 'コンテキストウィンドウ': '1,000,000 tokens (≈ 750,000語 — 1つのコンテキスト内のすべての本)' }, { 'モデル': 'Gemini 1.5 Pro', 'コンテキストウィンドウ': '1,000,000 tokens' }, { 'モデル': 'ローカルモデル (Ollama, LM Studio)', 'コンテキストウィンドウ': '設定可能な4k～128k+、利用可能なVRAMで制限' }], tableFormat: true },
  contextWindowNote: { content: 'すべてのモデルで原則は同じです。ウィンドウの外のすべては見えません。' },
  whyForgets: { title: 'AIが「忘れる」理由', content: ['**会話内のトークンの合計数（システムプロンプト+チャット履歴+ユーザー入力+ツール+予想出力）がコンテキストウィンドウを超える場合、古い部分は切り詰められ、要約されるか、完全に削除されます。**', 'これは人間の忘却のような記憶喪失ではありません。モデルは「考えてから忘れる」わけではありません。文字通り切り詰められたテキストを見ません。モデルの入力空間に存在しなくなります。', '**コンテキスト限界に達した場合の一般的な症状：'], items: ['AIが30メッセージ前に与えた指示を無視または矛盾する', '長い創作ストーリーでは、モデルはあなたが以前確立したキャラクター名、詳細、または制約を忘れます', '多くのターンにわたる研究チャットでは、事実が混同されるか、モデルが情報を再発明します', 'AIが突然トーンを変更したり、説明なしに元の制約に違反する'], image: '/images/context-window-token-flow-ja.svg', imageCaption: 'コンテキストウィンドウはスライディングウィンドウのように機能します。新しいトークンが古いものを押し出します。ウィンドウが満杯になると、モデルは以前のコンテンツを見ることができません。' },
  whatHappens: { title: '実際に何が起こっているのか', content: 'ほとんどのチャットインターフェースは次のいずれかの戦略を使用します:', numberedItems: ['**最も古いメッセージを削除** — 最新のNメッセージがウィンドウに適合します。古いメッセージは完全に破棄されます', '**以前の会話を要約** — システムは早期のメッセージを簡潔な要約（「以前、あなたはX、Y、Z…について議論しました」）に圧縮してコンテキストを保持します', '**システム/開発者プロンプトをピン止め** — システムメッセージは固定されたままで、ユーザーメッセージはローテーションします'] },
  whatHappensNote: { content: 'これらすべては「要点」を保持しますが、具体的な詳細は失われます。モデルが元の指示を見なくなったとき、それに従うことはできません。' },
  hallucinations: { title: 'コンテキストウィンドウとハルシネーション', content: ['**コンテキスト過負荷はハルシネーションを増加させます。元の情報が見えなくなったとき、モデルはもっともらしい推測でギャップを埋めるためです。**', 'パターンは次のようになります。50メッセージ前に言及した何かをAIに参照するよう求めます。しかしそのメッセージはコンテキストウィンドウから回転しました。モデルは実際の事実にアクセスできないため、現在のコンテキストから推測することに基づいて、もっともらしく聞こえる答えを生成します。結果：捏造。', 'これが高コンテキストの長いチャットが、集中した短い交換よりも多くのハルシネーションを生成する理由です。モデルは推論能力を失っていません。不完全な情報で機能しています。', '**相互作用は直接的です：** コンテキストが少ない → グラウンディングが不足している → ハルシネーションリスクが増加します。', 'この効果は、すでに確率性を高める高い温度とtop-pの設定で強化されます。[Fundamentals: Temperature and Top-P: Control AI Creativity]を参照してください。パラメータチューニングがハルシネーションとどのように相互作用するかを理解するために。'] },
  promptDesign: { title: 'プロンプト設計がウィンドウ内にとどまるのをどのように支援するか', content: '**プロンプトを戦略的に構造化することにより、固定コンテキスト予算内でより多くを達成できます。**', image: '/images/context-window-prompt-strategies-ja.svg', imageCaption: 'プロンプト最適化により30～50%のトークン削減：前のターンから冗長なコンテキストを削除することで、ウィンドウを、モデルが知る必要があることに焦点を当てた状態に保ちます。' },
  promptDesignStrategies: { content: ['**重要な指示を前に配置します。** 最も重要な制約、ルール、定義をシステムプロンプトまたはすべての最初のユーザーメッセージに配置します。これらは、20ターン後に埋め込まれた指示よりもコンテキストから削除される可能性が低いです。', '**繰り返しを避ける。** 何かを一度説明したら、もう一度貼り付けないでください。代わりに、それを参照してください。「上記のサマリーで説明したように…」これはトークンを節約します。', '**明確に要約してください。** モデルに、これまでの主要な決定、制約、または事実を要約するように求めます。その後、分散された以前のコンテキストに依存するのではなく、その要約から次の応答を構築します。', '**ターンに焦点を当てておきます。** 単一の複数トピックのモノローグはコンテキストを効率的に使用しません。分離された、狭いスコープの交換に分割します。'] },
  contextTable: { title: 'コンテキストウィンドウサイズ (2026)', rows: [{ '習慣': 'すべてのターンで長いコンテキストを繰り返す', 'コンテキスト影響': '🔴 高い無駄' }, { '習慣': 'システムプロンプトで前に指示を配置', 'コンテキスト影響': '🟢 効率的' }, { '習慣': '続行前に明示的なリキャップを要求', 'コンテキスト影響': '🟢 焦点を保持' }, { '習慣': 'ポイントを再貼り付けする代わりに参照', 'コンテキスト影響': '🟢 トークンを節約' }, { '習慣': '5つの関連のない質問を持つ単一のモノローグ', 'コンテキスト影響': '🔴 フォーカスを混乱させる' }, { '習慣': '5つの別個の、焦点を当てた交換', 'コンテキスト影響': '🟢 明確、効率的' }], tableFormat: true, image: '/images/context-window-size-comparison-ja.svg', imageCaption: 'コンテキストウィンドウサイズ(2026年)：Geminiは1Mトークン（Claude比8倍、Mistral比32倍）をサポート — この違いが、コード全体がリクエストに収まるかを決定します。' },
  longDocuments: { title: '長いドキュメントの操作', content: ['**本全体または数百ページのPDFを単一のコンテキストウィンドウに貼り付けることは、Claude Opusの1MトークンウィンドウでもClaudeが複数の異なるセクションに効果的に焦点を当てることができないため、非効率です。**', '1,000ページの本≈250,000トークン。技術的には、Claude Opusはそれを摂取できます。実際には、モデルの推論は、大きく異なるセクション全体で質問に答えるよう求められたときに低下します。まるで人が一度に本全体を読んでから、50ページ、200ページ、400ページから特定の詳細を思い出すよう求められるようなものです。想起はかすかになります。', '**長いドキュメントの方が良い方法：'], numberedItems: ['**セクションを順序付けて処理します。** チャプターまたはセクションを一度に抽出および分析します。セクションあたり焦点を当てた質問をします。「セクション3の主な結論は何ですか？」次に次のセクションに移動します。', '**階層的要約。** ページ1–10から主要なポイントを抽出してから、ページ11–20から、これらの要約をチャプターレベルの要約に結合します。次に、チャプターをドキュメントレベルの要約に結合します。これにより、ドキュメントは本質的な事実に削減され、関係を保持します。', '**構造化された抽出。** 高いレベルの質問をする前に、ドキュメントを表、JSON、または箇条書きリストに変換します。これは情報を圧縮します。50ページの製品仕様を貼り付ける代わりに、仕様を構造化テーブルに抽出してから、テーブルについて質問します。', '**RAG（検索拡張生成）を使用します。** 本当に大きなドキュメントセット（100+ページ）の場合、検索ベースのシステムがより効果的です。[Techniques: RAG Explained: How to Ground AI Answers in Real Data]を参照してください。すべてを一度に読み込む代わりに、関連するセクションを取得する方法については。'] },
  promptQuorumContext: { title: 'PromptQuorumがコンテキスト管理を支援する方法', content: 'PromptQuorumの構築経験から、コンテキスト制限の近くで作業することは難しいことに気づきました。各モデルには異なる制限、切り詰め動作、価格設定、および（ローカルLLMの場合）VRAMの要件があるためです。PromptQuorumは、これを透過的かつ意図的にするのに役立ちます。' },
  contextWindowAdjustment: { title: 'ローカルLLMのコンテキストウィンドウ調整', content: ['LM StudioまたはOllamaでモデルを実行すると、コンテキストウィンドウサイズを構成できます。デフォルトでは、ツールはそれをモデルの最大値に設定することが多い（たとえば、7Bモデルの場合は32k）。しかし、それはあなたが必要とするものはめったにありません。', 'PromptQuorumはLM Studioと統合されており、タスクごとにコンテキストウィンドウを調整できます。軽くて高速なQ&Aの場合は4kを選択します。深いドキュメント分析の場合は32kを選択します。長い会話の場合は64kを選択します。これにより、トレードオフが構成ファイルに隠されるのではなく、明示的になります。'] },
  contextOverflowChecks: { title: '自動コンテキストオーバーフローチェック', content: ['PromptQuorumは*を送信する前に確認します：システムプロンプト+現在の会話履歴+新しい入力+予想される出力の長さが与えられている場合、それは各モデルに設定されたコンテキストウィンドウに適合しますか？', 'オーバーフロー可能性がある場合、PromptQuorumはあなたを警告するか、送信する前に会話をトリム/要約するよう求めます。サプライズの切り詰めはもうありません。AIが「忘れた」理由について推測していません。'] },
  vramTradeoff: { title: 'コンテキストウィンドウ ↔ VRAM Trade-off', content: ['ローカルモデルの場合、より大きなコンテキストウィンドウはより多くのVRAMを要求します。4kコンテキストウィンドウを備えた7Bパラメータモデルには約14GB VRAMが必要です。同じモデルの128kコンテキストウィンドウには32GB+が必要です。さらに進むと、GPUはメモリが不足し、クラッシュするか、CPU推論に戻ります（これは10–100倍遅い）。', 'PromptQuorumはこの関係を示します。「このコンテキストウィンドウサイズはハードウェア上で約28GB VRAMを使用します。利用可能な16GBがあります。」その後、推論中のクラッシュを発見するのではなく、タスクとハードウェアにコンテキストウィンドウを適切に調整できます。'] },
  multiModelAwareness: { title: 'マルチモデル認識', content: 'GPT-4o（128kウィンドウ）、Claude（200kウィンドウ）、ローカル7Bモデル（選択した32kウィンドウ）にプロンプトをディスパッチすると、PromptQuorumは自動的にプロンプトを3つの境界内に保ちます。1つのプロンプト、複数のモデル、手動の書き換えなし。' },
  recipes: { title: 'コンテキスト管理のための実用的なレシピ' },
  recipe1: { title: 'レシピ1：1つのプロジェクトについての長いチャット', content: '**目標：** 以前の決定を失わずに、単一のプロジェクトに関するマルチターン会話を維持します。', numberedItems: ['システムプロンプトに、プロジェクトの主要な制約（スコープ、オーディエンス、トーン、技術的制限）を一度埋め込みます。繰り返さないでください。', '10～15の交換ごとに、モデルに現在の状態を要約するよう求めます。「これまでのところ、最も重要な5つの決定は何ですか？」', 'その要約を次のターンのコンテキストとして使用してください。分散された以前のメッセージに依存するのではなく。', 'PromptQuorumで、32k–64kのコンテキストウィンドウを設定し、オーバーフロー警告を有効にして、いつ要約するかを知ることができます。'] },
  recipe2: { title: 'レシピ2：長いレポートの分析', content: '**目標：** 50～100ページのドキュメントから洞察を抽出します。', numberedItems: ['ドキュメントを3～5セクション（チャプター、パーツ）に分割します。', '各セクションについて、焦点を当てたプロンプトを作成します。「このセクションからの主要な発見を5つの箇条書きにまとめてください。」', '各セクションから5つのサマリーを収集します。', '最後のターンで、「これらのセクションサマリーが与えられている場合、全体的な結論は何ですか？」と聞きます。', 'コンテキスト制限内でうまく留まり、「本に迷った」問題を回避しました。'] },
  recipe3: { title: 'レシピ3：コンテキストウィンドウの端でのプロンプト作成', content: '**目標：** ほぼ完全なコンテキストウィンドウをオーバーフローなしで使用します。', numberedItems: ['予算を計算します：コンテキストウィンドウサイズ−システムプロンプトトークン−予想出力トークン=入力+履歴に利用可能なトークン。', '例：128kウィンドウ、200トークンシステムプロンプト、1k出力バッファ=126.8k利用可能なトークン。', '送信前に、PromptQuorumで確認してください。「この入力は何個のトークンがかかりますか？」', '制限に近い場合、最も古いターンをトリムするか、続行する前にそれをまとめてください。', 'これにより、制限をランダムに打つのではなく、意図的に限界の近くで動作させます。'] },
  recipe4: { title: 'レシピ4：限られたVRAMを備えたローカルLLM', content: '**目標：** クラッシュなしでローカルモデルを効果的に実行します。', numberedItems: ['モデルのVRAMに対して保守的なコンテキストウィンドウ（8k–16k）から始めます。', 'PromptQuorumの設定で、そのウィンドウサイズでのVRAM要件をメモします。', 'タスクを実行します。オーバーフロー時は、会話をまとめてサマリーから再開します。', '制限に近づくことがない場合は、コンテキストウィンドウをゆっくり増やして再テストしてください。', 'ハードウェアとタスク用にモデルの「適切にサイズ調整された」コンテキストウィンドウを見つけます。'] },
  commonMistakes: { title: 'コンテキストウィンドウでの一般的な間違い', items: ['"モデルはすべての以前のチャットを覚えています。"いいえ。新しい会話はすべて、過去のチャットからゼロコンテキストで開始されます。1つのチャット内でも、交換がコンテキストウィンドウを超えると、それは終わります。', '"毎ターン同じ長いコンテキストを貼り付けます。"これはトークンを無駄にし、役に立たない — モデルはまだ300ページ上で効果的に推論できません。代わりに、サマリーをまとめて参照してください。', '"長いチャットで5つの異なるプロジェクトを混ぜます。"各プロジェクトはトークンのために競います。コンテキストが満杯になると、詳細がトリミングされます。プロジェクトごとに別のチャットを使用してください。', '"AIは推論が悪い — temperature または top-pである必要があります。"かもしれません。しかし最初にコンテキストウィンドウを確認してください。モデルが元の制約を見なくなった場合、それはパラメータの問題ではなく、情報の欠落です。', '"ローカルLLMのコンテキストウィンドウを最大化します。"その後、VRAMが不足します。プロセスがクラッシュし、推論は遅いCPUモードに戻ります。代わりにコンテキストをハードウェアに合わせて設定してください。', '"アプリはオーバーフローについて警告しました。"警告を信じてください。オーバーフローは静かな切り詰め、隠されたハルシネーション、および浪費されたトークンにつながります。まず要約してください。'] },
  faq: { title: 'FAQ', faqs: [{ q: 'モデルは以前のチャットを記憶していますか?', a: 'いいえ。新しい会話セッションはすべてゼロ履歴で開始されます。モデルは現在のコンテキストウィンドウ内のトークンのみを見ます。以前のチャットを参照したい場合、関連部分を現在の会話にコピーする必要があります。' }, { q: 'なぜAIは20メッセージ前に与えた指示を無視しましたか？', a: 'その指示はおそらくコンテキストウィンドウから外に落ちました。モデルはそれを見なくなったため、従うことはできません。解決策：システムプロンプトで重要な指示を繰り返すか、会話の途中でモデルに指示を再キャップして再埋め込みするよう求めます。' }, { q: 'より大きなコンテキストウィンドウは常に良いですか？', a: 'いいえ。より大きなウィンドウを使用すると、より多くのコンテンツを含めることができますが、コストも増加します（処理するトークンが多い）。ローカルモデルの場合、VRAM使用量も増加します。タスクに適したコンテキストウィンドウを選択してください。単純なQ&Aの場合は4k、長い会話の場合は32k、ドキュメント分析の場合は128k+。大きいことは「良い」わけではありません — *適切*が良いです。' }, { q: 'コンテキスト制限に達したことをどうやって知りますか？', a: 'モデルの応答はトーンを変更し、以前の指示に矛盾するか、以前に設定した詳細の追跡を失います。PromptQuorumのコンテキストオーバーフロー確認を送信する前に使用してください。制限に近づいていることを警告します。' }, { q: 'コンテキストウィンドウサイズはローカルモデルのVRAM使用にどのように影響しますか？', a: 'より大きなコンテキストウィンドウはおよそ比例してより多くのVRAMを使用します。コンテキストウィンドウを2倍にすると、VRAMの使用量がおおよそ2倍になります。4kコンテキストの7Bモデル≈14GB VRAM。32kコンテキスト≈28GB VRAM。PromptQuorumのVRAM計算機をチェックしてください。ハードウェアの上限を知ることができます。' }, { q: 'PromptQuorumのようなツールはコンテキストオーバーフローを防止できますか？', a: 'はい。PromptQuorumはプロンプトのトークン数、構成されたコンテキストウィンドウ、モデルの実際の制限を確認してから、オーバーフローが可能性がある場合は送信前に警告します。その後、トリミングまたは要約してから続行できます。' }, { q: '異なるモデルは長いコンテキストを異なる方法で処理しますか?', a: 'はい。Claude 3.5 Sonnetは200kトークンにわたって焦点を保ちます。GPT-4oは128kで堅牢です。より小さなモデル（たとえばLLaMA 2 7B）は、技術的にはコンテキストウィンドウが大きい場合でも、8k–16k以上の推論の一貫性を失うことがあります。最も安全なアプローチ：特定のモデルとタスクをテストしてください。' }] },
  relatedReading: { title: '関連する読み物', items: ['[Fundamentals: The 5 Building Blocks Every Prompt Needs] — コンテキストが制約になる前にプロンプトを構造化する方法', '[Fundamentals: AI Hallucinations: Why AI Makes Things Up] — 欠落しているコンテキストがハルシネーションリスクを増加させる理由', '[Techniques: RAG Explained: How to Ground AI Answers in Real Data] — 生のコンテキストではなく検索を使用して、本当に大きなドキュメントセットを処理する方法'] },
  sources: { title: 'ソース', items: ['[OpenAI, 2024. "API reference: Models and context windows"](https://platform.openai.com/docs/models) — トークン制限と価格設定に関するモデルごとの公式ドキュメント', '[Anthropic, 2024. "Claude model context windows and token costs"](https://docs.anthropic.com/en/docs/about-claude/models/overview) — Claudeの200kコンテキストウィンドウと2026年3月Opus 4.6 1Mコンテキストアナウンス', '[Raffel et al., 2020. "Exploring the Limits of Transfer Learning with a Unified Text-to-Text Transformer"](https://arxiv.org/abs/1910.10683) — トランスフォーマーのコンテキストウィンドウ効果に関する基礎研究'] },
}

export const contextWindowsZh: Record<string, PESection> = {
  definition: { title: '上下文窗口解释：为什么AI会忘记', content: '**LLM没有长期记忆——它们只能"看到"最近令牌的滑动窗口，此窗口外的任何内容都会被遗忘或压缩。** 本文解释了这对你的提示意味着什么，以及如何在这些限制内（和外）工作。' },
  tldr: { title: '关键要点', isTldr: true, items: ['**上下文窗口** = 模型一次可以处理的最大令牌数；超过后，较旧的内容会被截断或总结', '**令牌≈4个字符**（平均）；4k上下文窗口≈3,000个普通文本单词', '模型不会"记住"以前的聊天——每次交互在其上下文窗口内重新开始', '**上下文过载增加幻觉**，因为当原始细节超出视野时，模型会用似是而非的猜测来填补空白', '**提示结构比运气更重要：** 将关键指导放在前面，避免重复，在继续之前总结长交换', '对于**本地LLM**，更大的上下文窗口需要更多VRAM——7B参数模型上的128k上下文模型可能需要32GB+的内存'] },
  whatIsContextWindow: { title: '什么是上下文窗口？', content: ['**上下文窗口是LLM在生成其下一个输出时可以考虑的最大文本量（以令牌衡量）。**', '将其视为模型在任何给定时刻的"可见文本"。当你向GPT-4o发送一条有128k令牌上下文窗口的消息时，该模型可以"看到"对话的最后128,000个令牌——大约96,000个单词。在此之前的任何内容对模型不可见，不会影响其回复。', '**令牌与单词：**令牌不是单词。平均而言，一个令牌≈4个字符或约0.75个单词。4,000令牌的上下文窗口≈3,000个普通英文文本单词。对于密集代码或日语等语言，比率是不同的——日文文本由于字符编码，每个单词需要大约2个令牌。', '**上下文窗口大小在模型中差异很大：'], rows: [{ '模型': 'GPT-3.5 Turbo', '上下文窗口': '4k令牌 (≈ 3,000个单词)' }, { '模型': 'GPT-4 Turbo', '上下文窗口': '128k令牌 (≈ 96,000个单词)' }, { '模型': 'Claude 3.5 Sonnet', '上下文窗口': '200k令牌 (≈ 150,000个单词)' }, { '模型': 'Claude Opus 4.6 (2026年3月)', '上下文窗口': '1,000,000令牌 (≈ 750,000个单词——一个上下文中的整本书)' }, { '模型': 'Gemini 1.5 Pro', '上下文窗口': '1,000,000令牌' }, { '模型': '本地模型 (Ollama, LM Studio)', '上下文窗口': '可配置4k至128k+，受可用VRAM限制' }], tableFormat: true },
  contextWindowNote: { content: '所有模型的原则都是相同的：窗口外的任何内容都是不可见的。' },
  whyForgets: { title: 'AI为什么会"忘记"', content: ['**当对话中的总令牌数（系统提示+聊天记录+用户输入+工具+预期输出）超过上下文窗口时，较旧的部分会被截断、总结或完全删除。**', '这不像人类遗忘那样的记忆丧失。模型不是"思考然后忘记"。它根本看不到截断的文本——它不再存在于模型的输入空间中。', '**达到上下文限制时的常见症状：'], items: ['AI忽视或矛盾了你30条消息前给出的指导', '在长创意故事中，模型会忘记你之前建立的角色名称、细节或约束', '在跨越多个轮次的研究聊天中，事实会混淆，或模型会重新发明信息', 'AI突然改变语气或违反你的原始约束，没有解释'], image: '/images/context-window-token-flow-zh.svg', imageCaption: '上下文窗口像滑动窗口一样工作：新Token将旧Token推出——一旦窗口满满，模型就无法看到之前的内容。' },
  whatHappens: { title: '实际发生的情况', content: '大多数聊天界面使用以下策略之一：', numberedItems: ['**删除最旧的消息** ——最近的N条消息适合窗口；较旧的消息被完全丢弃', '**总结较早的对话** ——系统将早期消息压缩为简短摘要（"之前，你讨论过X、Y、Z……"）以保留上下文', '**固定系统/开发人员提示** ——系统消息保持固定，而用户消息进行轮换'] },
  whatHappensNote: { content: '所有这些都保留了"要点"，但丢失了具体细节。当模型不再看到原始指导时，它无法遵循。' },
  hallucinations: { title: '上下文窗口和幻觉', content: ['**上下文过载会增加幻觉，因为当原始信息不再可见时，模型会用似是而非的猜测来填补空白。**', '以下是模式：你要求AI回到你50条消息前提到的东西。但该消息已从上下文窗口轮换出去。模型无法访问实际事实，因此它根据从当前上下文推断的内容生成听起来似是而非的答案。结果：捏造。', '这就是为什么高上下文、长对话聊天通常会产生比集中的短交换更多的幻觉。模型没有失去推理能力——它正在处理不完整的信息。', '**相互作用是直接的：** 减少上下文→缺乏锚定→增加幻觉风险。', '这种效应与更高的温度和top-p设置相复合，这已经增加了随机性。请参阅[Fundamentals: Temperature and Top-P: Control AI Creativity]以了解参数调整如何与幻觉相互作用。'] },
  promptDesign: { title: '提示设计如何帮助你保持在窗口内', content: '**战略性地构建提示可以让你在固定的上下文预算内完成更多工作。**', image: '/images/context-window-prompt-strategies-zh.svg', imageCaption: '提示词优化节省30–50%令牌：从之前的轮次中删除冗余上下文，保持窗口专注于模型需要了解的内容。' },
  promptDesignStrategies: { content: ['**将关键指导放在前面。** 在系统提示或第一条用户消息中放置最重要的约束、规则和定义。这些不太可能像20个轮次后埋没的指导那样超出上下文。', '**避免重复。** 如果你已经解释过一次，不要再粘贴一遍。相反，参考它："正如我们在上面的摘要中讨论的……"这可以节省令牌。', '**明确总结。** 要求模型总结迄今为止的关键决定、约束或事实。然后从该摘要构建下一个响应，而不是依赖分散的早期上下文。', '**保持转数集中。** 单个多主题独白会低效地使用上下文。将其分解为单独的、范围狭窄的交换。'] },
  contextTable: { title: '上下文窗口大小 (2026)', rows: [{ '习惯': '在每个轮次重复长上下文', '上下文影响': '🔴 高浪费' }, { '习惯': '在系统提示中将指导放在前面', '上下文影响': '🟢 高效' }, { '习惯': '在继续之前要求明确的复述', '上下文影响': '🟢 保留焦点' }, { '习惯': '引用早期要点而不是重新粘贴', '上下文影响': '🟢 节省令牌' }, { '习惯': '带有5个无关问题的单一独白', '上下文影响': '🔴 混淆焦点' }, { '习惯': '5个单独的、集中的交换', '上下文影响': '🟢 清晰、高效' }], tableFormat: true, image: '/images/context-window-size-comparison-zh.svg', imageCaption: '上下文窗口大小(2026年)：Gemini支持1M令牌（比Claude多8倍，比Mistral多32倍）——这种差异决定了整个代码库是否可以容纳在一个请求中。' },
  longDocuments: { title: '处理长文档', content: ['**将整本书或数百页的PDF粘贴到单个上下文窗口中是低效的，即使对于Claude Opus的1M令牌窗口，因为模型无法同时有效地关注多个不同的部分。**', '一本1,000页的书≈250,000令牌。从技术上讲，Claude Opus可以摄取它。实际上，当被要求跨大部分不同的部分回答问题时，模型的推理会降低——就像要求一个人在一个坐位读完整部小说，然后回忆第50、200和400页的特定细节一样。回忆变得模糊。', '**处理长文档的更好方法：'], numberedItems: ['**顺序处理部分。** 一次提取和分析一个章节或部分。提出关注的问题：第3部分的主要结论是什么？"然后进行下一部分。', '**分层总结。** 从第1-10页中提取要点，然后从第11-20页，将这些摘要合并为章节级别的摘要。然后将章节合并为文档级别的摘要。这将文档简化为其基本事实，同时保留关系。', '**结构化提取。** 在提出更高层次的问题*之前*，将文档转换为表格、JSON或项目符号列表。这压缩信息：不是粘贴50页的产品规格，而是将规格提取到结构化表格中，然后询问关于表格的问题。', '**使用RAG（检索增强生成）。** 对于真正大型的文档集（100+页），基于检索的系统效果更好。请参阅[Techniques: RAG Explained: How to Ground AI Answers in Real Data]了解如何检索相关部分，而不是一次性加载所有内容。'] },
  promptQuorumContext: { title: 'PromptQuorum如何帮助你管理上下文', content: '根据我构建PromptQuorum的经验，我发现在上下文限制附近工作很困难，因为每个模型都有不同的限制、截断行为、定价，以及（对于本地LLM）VRAM要求。PromptQuorum帮助你使这变得透明和有意。' },
  contextWindowAdjustment: { title: '本地LLM的上下文窗口调整', content: ['在LM Studio或Ollama中运行模型时，可以配置上下文窗口大小。默认情况下，工具通常将其设置为模型的最大值（例如，7B模型为32k）。但这很少是你需要的。', 'PromptQuorum与LM Studio集成，允许你按任务调整上下文窗口：为轻量级快速问答选择4k；为深度文档分析选择32k；为长对话选择64k。这使权衡明确，而不是隐藏在配置文件中。'] },
  contextOverflowChecks: { title: '自动上下文溢出检查', content: ['PromptQuorum在*你发送之前*检查：给定系统提示+当前对话历史+你的新输入+预期输出长度，这是否适合为每个模型配置的上下文窗口？', '如果溢出可能，PromptQuorum会警告你或提示你在发送之前修剪/总结对话。不再有意外截断。不再猜测AI为什么"忘记了"。'] },
  vramTradeoff: { title: '上下文窗口 ↔ VRAM权衡', content: ['对于本地模型，更大的上下文窗口需要指数级更多的VRAM。具有4k上下文窗口的7B参数模型需要约14GB VRAM。相同模型的128k上下文窗口需要32GB+。进一步推进，GPU会耗尽内存、崩溃或回退到CPU推理（慢10–100倍）。', 'PromptQuorum向你显示这种关系："这个上下文窗口大小将在你的硬件上使用约28GB VRAM。你有16GB可用。"然后你可以为你的任务和硬件恰当地调整上下文窗口，而不是在推理中途发现崩溃。'] },
  multiModelAwareness: { title: '多模型意识', content: '当你将一个提示发送到GPT-4o（128k窗口）、Claude（200k窗口）和本地7B模型（你选择的32k窗口）时，PromptQuorum会自动将你的提示保持在所有三个边界内。一个提示，多个模型，无需手动重写。' },
  recipes: { title: '上下文管理的实用配方' },
  recipe1: { title: '配方1：关于一个项目的长聊天', content: '**目标：** 维持关于单个项目的多轮对话，不失去早期决定。', numberedItems: ['在系统提示中，嵌入项目的关键约束（范围、受众、语气、技术限制）一次。不要重复。', '每10-15次交换后，要求模型总结当前状态："迄今为止我们做出的5个最重要的决定是什么？"', '使用该摘要作为你的下一个轮次的上下文，而不是依赖分散的早期消息。', '在PromptQuorum中，设置32k-64k的上下文窗口并启用溢出警告，以便你知道何时总结。'] },
  recipe2: { title: '配方2：分析长报告', content: '**目标：** 从50-100页文档中提取见解。', numberedItems: ['将文档分成3-5个部分（章节、部分）。', '对于每个部分，编写一个集中的提示："将本部分的主要发现总结为5个项目。"', '从每个部分收集这5个摘要。', '在最后的轮次，问："给定这些部分摘要，总体结论是什么？"', '你在上下文限制内保持良好，避免了"迷失在书中"的问题。'] },
  recipe3: { title: '配方3：在上下文窗口边缘提示', content: '**目标：** 不溢出地使用几乎完整的上下文窗口。', numberedItems: ['计算你的预算：上下文窗口大小−系统提示令牌−预期输出令牌=可用于你的输入+历史的令牌。', '示例：128k窗口，200令牌系统提示，1k输出缓冲=126.8k可用令牌。', '发送之前，在PromptQuorum中检查："此输入需要多少令牌？"', '如果接近限制，修剪最旧的轮次或在继续前总结它。', '这使你在意图上靠近限制运行，而不是随意击中它。'] },
  recipe4: { title: '配方4：VRAM有限的本地LLM', content: '**目标：** 有效运行本地模型，不崩溃。', numberedItems: ['为你的模型VRAM开始一个保守的上下文窗口（8k-16k）。', '在PromptQuorum的设置中，在该窗口大小处注意VRAM要求。', '运行你的任务。如果你有溢出，总结对话并从摘要重新开始。', '如果你永远不会接近极限，缓慢增加上下文窗口并重新测试。', '为你的硬件和任务找到你的模型"合适尺寸的"上下文窗口。'] },
  commonMistakes: { title: '上下文窗口的常见错误', items: ['"模型记住我所有以前的聊天。"它没有。每个新对话始于零历史，来自过去的聊天。即使在一个聊天中，一旦你的交换超过上下文窗口，它就消失了。', '"我会在每个轮次粘贴相同的长上下文。"这浪费令牌并无帮助——模型仍然无法有效地推理超过300页。相反，总结并参考摘要。', '"我会在一个长对话中混淆五个不同的项目。"每个项目竞争令牌。当上下文填满时，细节会被截断。使用每个项目的单独对话。', '"AI擅长推理——必须是温度或top-p。"也许。但首先检查上下文窗口。如果模型不再看到原始约束，这不是参数问题；这是信息缺失。', '"我会在我的本地LLM上最大化上下文窗口。"然后你耗尽VRAM，进程崩溃，推理回退到慢CPU模式。设置上下文以匹配你的硬件。', '"应用警告我溢出，但我还是发送了。"相信警告。溢出导致无声截断、隐藏幻觉和浪费的令牌。首先总结。'] },
  faq: { title: '常见问题', faqs: [{ q: '模型记住我以前的聊天吗？', a: '不。每个新对话会话从零历史开始。模型只看到当前上下文窗口内的令牌。如果要参考以前的聊天，必须将相关部分复制到当前对话中。' }, { q: '为什么AI忽视了我20条消息前给出的指导？', a: '该指导可能已从上下文窗口滑出。模型不再看到它，因此无法遵循它。解决方案：在系统提示中重复关键指导，或要求模型在对话中重新封闭和重新嵌入指导。' }, { q: '更大的上下文窗口总是更好吗？', a: '不是。更大的窗口允许包含更多内容，但也增加成本（要处理的令牌更多）以及对于本地模型，VRAM使用。选择适合你任务的上下文窗口：4k用于简单问答，32k用于长对话，128k+用于文档分析。更大不是"更好"——*适当*是更好。' }, { q: '我如何知道何时达到上下文限制？', a: '模型的响应改变语气，与早期指导矛盾，或丢失你之前设置的详细信息的跟踪。在发送前使用PromptQuorum的上下文溢出检查——如果你接近限制，它会警告你。' }, { q: '上下文窗口大小如何影响本地模型的VRAM？', a: '更大的上下文窗口大约按比例使用更多VRAM：将上下文窗口加倍大约加倍VRAM使用。4k上下文的7B模型≈14GB VRAM；32k上下文≈28GB VRAM。检查PromptQuorum的VRAM计算器以了解硬件的上限。' }, { q: 'PromptQuorum之类的工具可以防止上下文溢出吗？', a: '可以。PromptQuorum检查你的提示的令牌数、你配置的上下文窗口和模型的实际限制，然后在溢出可能时在发送前警告你。然后你可以在继续之前修剪或总结。' }, { q: '不同的模型对长上下文的处理方式不同吗？', a: '是的。Claude 3.5 Sonnet在200k令牌上保持焦点良好。GPT-4o在128k是扎实的。较小的模型（例如LLaMA 2 7B）有时在8k-16k之外失去推理一致性，即使他们的上下文窗口在技术上更大。最安全的方法：测试你的特定模型和任务。' }] },
  relatedReading: { title: '相关阅读', items: ['[Fundamentals: The 5 Building Blocks Every Prompt Needs] — 在上下文成为约束之前如何构建提示', '[Fundamentals: AI Hallucinations: Why AI Makes Things Up] — 缺少上下文为什么增加幻觉风险', '[Techniques: RAG Explained: How to Ground AI Answers in Real Data] — 如何用检索而不是原始上下文处理真正大的文档集'] },
  sources: { title: '来源', items: ['[OpenAI, 2024. "API reference: Models and context windows"](https://platform.openai.com/docs/models) — 关于每个模型令牌限制和定价的官方文档', '[Anthropic, 2024. "Claude model context windows and token costs"](https://docs.anthropic.com/en/docs/about-claude/models/overview) — Claude 200k上下文窗口和2026年3月Opus 4.6 1M上下文公告', '[Raffel et al., 2020. "Exploring the Limits of Transfer Learning with a Unified Text-to-Text Transformer"](https://arxiv.org/abs/1910.10683) — 关于变压器中的上下文窗口效应的基础研究'] },
}
